import React from 'react';

// Componente Hero - Secção inicial com carrossel de imagens e texto de boas-vindas
function Hero() {
  return (
    <section id="hero" className="hero">
      <div id="carousel-track" className="carousel-track">
        {/* Slide ativo por defeito na Fase 2 */}
        <div 
          className="carousel-slide" 
          style={{ backgroundImage: "url('media/hero.png')" }}
        ></div>
      </div>

      {/* Controlos do carrossel */}
      <div className="hero-controls">
        <button id="prev" className="carrousel-btn">&#8249;</button>
        <button id="forward" className="carrousel-btn">&#8250;</button>
      </div>

      {/* Conteúdo sobreposto */}
      <div className="hero-overlay">
        <div className="container hero-content">
          <h1 data-i18n="hero_title">Centro Académico Clínico dos Açores</h1>
          <p data-i18n="hero_text">
            Excelência clínica com estreita integração entre prática clínica, educação e investigação.
          </p>
          <a href="#contactos" className="btn btn-primary" data-i18n="hero_btn">
            Junta-te a nós
          </a>
        </div>
      </div>
    </section>
  );
}

export default Hero;

import React from 'react';

// Componente About - Secção "Sobre Nós"
function About() {
  return (
    <section id="sobre" className="section">
      <div className="container about-flex">
        <div className="about-text">
          <span className="subtitle" data-i18n="sobre_subtitle">SOBRE NÓS</span>
          <h2 data-i18n="sobre_title">Centro Académico Clínico</h2>
          <p data-i18n="sobre_text">
            O Centro Académico Clínico dos Açores nasce da parceria entre o Governo Regional e a Universidade dos Açores para potenciar o setor da saúde no arquipélago. Unimos o saber académico à realidade hospitalar, promovendo a investigação e a formação contínua de profissionais e estudantes. O nosso foco é claro: inovação científica aplicada para garantir o bem-estar e a melhor qualidade de vida dos nossos doentes.
          </p>
        </div>
        <div className="about-image">
          <img src="media/sobre_nos.png" alt="Médicos em reunião" />
        </div>
      </div>
    </section>
  );
}

export default About;

import React from 'react';

// Componente Partners - Logos dos parceiros da clínica
function Partners() {
  return (
    <section className="section partners-section">
      <div className="container">
        <h3 data-i18n="parceiros_title">Os nossos parceiros</h3>
        <div className="partners-flex">
          <a href="https://www.uac.pt/">
            <img src="media/uac.png" alt="Universidade dos Açores" />
          </a>
          <a href="https://www.facebook.com/p/UAcESS-Escola-Superior-de-Sa%C3%BAde-Universidade-dos-A%C3%A7ores-100063229659438/?locale=pt_BR">
            <img src="media/ess.png" alt="Escola Superior de Saúde" />
          </a>
          <a href="https://www.facebook.com/hdespd/?locale=pt_PT">
            <img src="media/hdes.jpg" alt="Hospital do Divino Espírito Santo" />
          </a>
        </div>
      </div>
    </section>
  );
}

export default Partners;

import React from 'react';

// Componente Stats - Secção de estatísticas e investigações (onde serão renderizados os gráficos D3.js)
function Stats() {
  return (
